/**
 * PostCSS plugin to fix invalid CSS selectors generated by Material Tailwind React
 * for Turbopack/Lightning CSS compatibility.
 * 
 * This plugin follows the official PostCSS plugin API:
 * https://github.com/postcss/postcss/blob/main/docs/plugin-development.md
 * 
 * Fixes selectors like: .\[\&_data-slot\=icon\]\:h-5 data-slot=icon{
 * To: .\[\&_data-slot\=icon\]\:h-5[data-slot=icon]{
 * 
 * @see https://nextjs.org/docs/app/building-your-application/styling/postcss
 */
function postcssFixMaterialTailwind() {
  return {
    postcssPlugin: 'postcss-fix-material-tailwind',
    // Use OnceExit to process all rules after the AST is complete
    // This is more efficient than processing rules one at a time
    OnceExit(root) {
      root.walkRules((rule) => {
        const originalSelector = rule.selector;
        
        // Fix the invalid selector pattern:
        // Pattern: .[\&_data-slot\=icon]\:h-5 data-slot=icon{
        // Should be: .[\&_data-slot\=icon]\:h-5[data-slot=icon]{
        
        // Match: escaped attribute selector followed by space and standalone "data-slot=value"
        const fixedSelector = originalSelector.replace(
          /(\[\\&_data-slot\\=[^\]]+\]\\:[^\s{]+)\s+data-slot=([^\s{]+)/g,
          (match, prefix, value) => {
            // Convert standalone attribute to proper attribute selector
            return `${prefix}[data-slot=${value}]`;
          }
        );
        
        if (fixedSelector !== originalSelector) {
          rule.selector = fixedSelector;
        }
      });
    },
  };
}

// Mark as PostCSS plugin (required by PostCSS plugin API)
postcssFixMaterialTailwind.postcss = true;

module.exports = postcssFixMaterialTailwind;

